import{_ as a,c as t,o as i,a2 as o}from"./chunks/framework.CIiVzG-O.js";const h=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"guide/privacy.md","filePath":"guide/privacy.md","lastUpdated":1783607180000}'),r={name:"guide/privacy.md"};function s(n,e,l,c,d,p){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p>NueZip is designed as a fully offline-first application. Your privacy is our priority.</p><h2 id="local-only-design" tabindex="-1">Local-Only Design <a class="header-anchor" href="#local-only-design" aria-label="Permalink to &quot;Local-Only Design&quot;">​</a></h2><ul><li>All archive operations — compression, extraction, conversion, encryption — run entirely on your Mac.</li><li>NueZip does not upload your files or data to any external servers.</li><li>No account or registration is required to use the app.</li><li>No internet connection is required for normal operation.</li></ul><h2 id="what-we-do-not-collect" tabindex="-1">What We Do Not Collect <a class="header-anchor" href="#what-we-do-not-collect" aria-label="Permalink to &quot;What We Do Not Collect&quot;">​</a></h2><ul><li>We do not collect your files, documents, or archive contents.</li><li>We do not track your activity, browsing behavior, or usage patterns.</li><li>We do not send any file metadata or personal information to external servers.</li><li>We do not include third-party analytics, advertising, or tracking SDKs.</li><li>We do not have any telemetry system.</li></ul><h2 id="what-data-is-stored-locally" tabindex="-1">What Data Is Stored Locally <a class="header-anchor" href="#what-data-is-stored-locally" aria-label="Permalink to &quot;What Data Is Stored Locally&quot;">​</a></h2><p>The following data is stored only on your device:</p><ul><li><strong>App settings</strong>: Theme, language preference, compression preferences</li><li><strong>License key</strong>: If purchased (stored securely in the local keychain)</li><li><strong>Recent files list</strong>: Recently opened archives for quick access</li><li><strong>Password records</strong>: Stored in your local keychain if you choose to save them</li><li><strong>Logs</strong>: Debug logs for troubleshooting (can be deleted at any time)</li></ul><h2 id="permissions-used-by-the-app" tabindex="-1">Permissions Used by the App <a class="header-anchor" href="#permissions-used-by-the-app" aria-label="Permalink to &quot;Permissions Used by the App&quot;">​</a></h2><ul><li><strong>Files and Folders</strong>: Required to read archive files and extract contents.</li><li><strong>Finder Extension</strong>: Optional, adds right-click context menu items in Finder.</li><li><strong>Notifications</strong>: Optional, for completion alerts on long-running tasks.</li></ul><p>You can manage these permissions in <strong>System Settings → Privacy &amp; Security</strong> at any time.</p><h2 id="in-app-purchases-license" tabindex="-1">In-App Purchases / License <a class="header-anchor" href="#in-app-purchases-license" aria-label="Permalink to &quot;In-App Purchases / License&quot;">​</a></h2><p>License purchases are processed by Apple via the Mac App Store. NueZip does not receive or store your payment information. License receipts are stored locally to verify ownership.</p><h2 id="third-party-services" tabindex="-1">Third-Party Services <a class="header-anchor" href="#third-party-services" aria-label="Permalink to &quot;Third-Party Services&quot;">​</a></h2><p>NueZip does not include any third-party analytics, advertising, or tracking services. The app is fully self-contained.</p><h2 id="privacy-requests" tabindex="-1">Privacy Requests <a class="header-anchor" href="#privacy-requests" aria-label="Permalink to &quot;Privacy Requests&quot;">​</a></h2><p>Since NueZip stores all data locally on your device, we do not hold any personal data on our servers. If you have questions about privacy, please contact us.</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>For privacy questions, open an issue at <a href="https://github.com/nuezip/nuezip/issues" target="_blank" rel="noreferrer">GitHub Issues</a> or email us.</p>',20)])])}const y=a(r,[["render",s]]);export{h as __pageData,y as default};
